import{_ as t,c as s,o as a,ag as i}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Docker Deployment","description":"","frontmatter":{"icon":"docker"},"headers":[],"relativePath":"docker-deployment.md","filePath":"docker-deployment.md"}'),n={name:"docker-deployment.md"};function o(l,e,r,d,c,p){return a(),s("div",null,e[0]||(e[0]=[i(`<h1 id="docker-deployment" tabindex="-1">Docker Deployment <a class="header-anchor" href="#docker-deployment" aria-label="Permalink to &quot;Docker Deployment&quot;">​</a></h1><p>BetterTaxi’s containerized architecture allows for fast and consistent deployment using <strong>Docker and Docker Compose</strong>. This is the <strong>preferred method</strong> for production, staging, and most development environments.</p><hr><h4 id="✅-why-choose-docker-deployment" tabindex="-1">✅ Why Choose Docker Deployment? <a class="header-anchor" href="#✅-why-choose-docker-deployment" aria-label="Permalink to &quot;✅ Why Choose Docker Deployment?&quot;">​</a></h4><ul><li><strong>Fast setup</strong> with a one-line script</li><li><strong>Environment consistency</strong> across machines and teams</li><li><strong>Zero manual dependency management</strong></li><li><strong>Ready for scaling</strong> in cloud environments</li><li><strong>Database persistence</strong> with Docker volumes</li></ul><hr><h4 id="📦-what-s-included-in-the-docker-stack" tabindex="-1">📦 What’s Included in the Docker Stack? <a class="header-anchor" href="#📦-what-s-included-in-the-docker-stack" aria-label="Permalink to &quot;📦 What’s Included in the Docker Stack?&quot;">​</a></h4><p>The included <code>docker-compose.yml</code> file provisions:</p><table tabindex="0"><thead><tr><th>Service</th><th>Purpose</th></tr></thead><tbody><tr><td><code>rider-api</code></td><td>Customer ride/parcel operations</td></tr><tr><td><code>driver-api</code></td><td>Driver-related logic</td></tr><tr><td><code>admin-api</code></td><td>Backend for the Admin Panel</td></tr><tr><td><code>payment-gateways</code></td><td>Processor for 22+ integrated gateways</td></tr><tr><td><code>mysql</code></td><td>Relational database (Docker volume-persisted)</td></tr><tr><td><code>redis</code></td><td>Caching and job queues</td></tr><tr><td><code>nginx</code></td><td>Serves frontend &amp; API routing</td></tr></tbody></table><hr><h4 id="🛡️-licensing-requirements" tabindex="-1">🛡️ Licensing Requirements <a class="header-anchor" href="#🛡️-licensing-requirements" aria-label="Permalink to &quot;🛡️ Licensing Requirements&quot;">​</a></h4><ul><li>Each license is tied to <strong>one public IP</strong>.</li><li>Changing IPs frequently or deploying to multiple machines will result in license conflicts or <strong>temporary lockouts</strong>.</li><li>A <strong>static IP VPS</strong> is required for Docker deployment.</li><li>Running locally (on laptops or desktops) may consume your license unintentionally.</li></ul><blockquote><p>💡 Tip: Contact support if you need a dev license slot for local experimentation.</p></blockquote><hr><h4 id="⚙️-installation-steps" tabindex="-1">⚙️ Installation Steps <a class="header-anchor" href="#⚙️-installation-steps" aria-label="Permalink to &quot;⚙️ Installation Steps&quot;">​</a></h4><p>Download &amp; Run the installation script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://uploads.ridy.io/install-bettertaxi.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><ul><li>Installs Docker and Docker Compose if missing</li><li>Applies default <code>.env</code> values from the included <code>.env.example</code></li><li>Builds and launches all containers</li></ul><blockquote><p>Advanced users can edit <code>.env</code> and <code>docker-compose.yml</code> before or after setup to customize ports, resource limits, or volumes.</p></blockquote><hr><h4 id="🌍-accessing-the-admin-panel" tabindex="-1">🌍 Accessing the Admin Panel <a class="header-anchor" href="#🌍-accessing-the-admin-panel" aria-label="Permalink to &quot;🌍 Accessing the Admin Panel&quot;">​</a></h4><p>Once setup completes, visit:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://yourdomain.com/admin/</span></span></code></pre></div><p>You will be guided through the <strong>Admin Installation Wizard</strong>, which includes:</p><ul><li>License key verification</li><li>Initial database setup</li><li>Admin user creation</li><li>Branding and system name input</li><li>Firebase &amp; map key configuration</li></ul><hr><h4 id="💾-data-persistence" tabindex="-1">💾 Data Persistence <a class="header-anchor" href="#💾-data-persistence" aria-label="Permalink to &quot;💾 Data Persistence&quot;">​</a></h4><ul><li><strong>MySQL data</strong> is stored in Docker volumes and remains safe across container restarts or rebuilds.</li><li>Logs and cache are not wiped unless volumes are explicitly deleted.</li></ul><hr><h4 id="🧠-resource-requirements" tabindex="-1">🧠 Resource Requirements <a class="header-anchor" href="#🧠-resource-requirements" aria-label="Permalink to &quot;🧠 Resource Requirements&quot;">​</a></h4><ul><li>The full stack uses approximately <strong>2 GB RAM on idle</strong></li><li>Ensure your VPS has at least: <ul><li><strong>2 GB RAM</strong></li><li><strong>2-core CPU</strong></li><li><strong>10 GB disk space</strong></li><li><strong>Static IP address</strong></li></ul></li></ul><hr><h4 id="📌-post-install-configuration-tasks" tabindex="-1">📌 Post-Install Configuration Tasks <a class="header-anchor" href="#📌-post-install-configuration-tasks" aria-label="Permalink to &quot;📌 Post-Install Configuration Tasks&quot;">​</a></h4><p>After installation:</p><ol><li>Log in to the Admin Panel</li><li>Go to: <ul><li><strong>Settings → SMS Providers</strong>: Choose and configure one of 8 available</li><li><strong>Settings → Payment Gateways</strong>: Select and set up from 22 integrated gateways</li><li><strong>Regions &amp; Pricing</strong>: Define your operational areas and fare structures</li></ul></li><li>(Optional) Upload your brand logo and set system-wide colors</li></ol><hr><h4 id="🔧-managing-your-deployment" tabindex="-1">🔧 Managing Your Deployment <a class="header-anchor" href="#🔧-managing-your-deployment" aria-label="Permalink to &quot;🔧 Managing Your Deployment&quot;">​</a></h4><p>Once installed, you can manage your services using Docker commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # View running containers</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Stream live logs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Restart all services</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> down</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Stop and remove containers (volumes are safe)</span></span></code></pre></div><blockquote><p>For advanced scaling or separation (e.g., moving MySQL or Redis to dedicated servers), edit the <code>docker-compose.yml</code> and <code>.env</code> accordingly.</p></blockquote>`,40)]))}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
